import React, { Component } from 'react'
import $ from 'jquery'
import url from './audio/gbqq.mp3' // 引入背景音乐文件


class Main extends Component {
    state = {
        date: {},
    }
    componentDidMount() {
        this.print();
        setInterval(() => {
            this.time(2020, 1, 24) // 你们的纪念日
        }, 1000
        )
        var audio = document.getElementById("audio");
        setTimeout(() => audio.play(), 7400) // 背景音乐在页面加载后，延迟播放的时长，单位：毫秒。
    }
    print = () => {
        $.fn.autotype = function () {
            var _this = $(this);
            var str = _this.html();
            // 正则替换代码行之间添加的多个空格，不去除换行输出会有明显的停顿：实际是在输出多个空格
            str = str.replace(/(\s){2,}/g, "$1");
            var index = 0;
            $(this).html('');
            var timer = function fn() {
                var args = arguments;
                var current = str.slice(index, index + 1);
                // html标签完整输出,如：<p>
                if (current == '<') {
                    index = str.indexOf('>', index) + 1;
                }
                else {
                    index++;
                }
                //位运算符: 根据setInterval运行奇偶次来判断是否加入下划线字符“_”，使输入效果更逼真
                if (index < str.length - 1) { //打印字符倒数第2个字符开始，不加下划线字符，以防止结束符可能会多输出一下划线字符
                    _this.html(str.substring(0, index) + (index & 1 ? '_' : ''));
                } else {
                    _this.html(str.substring(0, index));
                    clearTimeout(timer);
                };
                setTimeout(fn, 200)
            };
            // 延迟1s开始
            setTimeout(timer, 1000);
        };
        $("#autotype").autotype();
    }
    time = (year, month, day) => {
        var dateNow = new Date();
        var dateJNR = new Date(year, month - 1, day);
        // var anniversary = parseInt((dateNow - dateJNR) / (365*24*3600*1000))
        var d = parseInt((dateNow - dateJNR) / (24 * 3600 * 1000));
        var hour = parseInt(((dateNow - dateJNR) / (3600 * 1000)) % 24);
        var minute = parseInt((dateNow - dateJNR) / (1000 * 60) % 60);
        var second = parseInt((dateNow - dateJNR) / 1000 % 60);
        this.setState({ date: { d: d, hour: hour, minute: minute, second: second } });
    };
    render() {
        const date = () => {
            if (this.state.date.d !== undefined) {
                const { d, hour, minute, second } = this.state.date
                return (<p>我们已经相识了: <span className="date-text">{d}</span> 天 <span className="date-text">{hour}</span> 小时 <span className="date-text">{minute}</span> 分 <span className="date-text">{second}</span> 秒 </p>
                )
            }
        }
        return (
            <div className="App animated bounceInLeft">
                <div className="date">{date()}</div>
                <div id="autotype">
                    <h1 style={{ fontWeight: 900 }}>Hi，小泽！</h1>
                    <p >在开始之前，先放首歌当背景音乐吧！Music!   </p>
                    <p>知道你生日后一直在想，该送什么呢，心里有几个答案，偶尔一两个告诉你，都被你否决了，也就一直没有问你家的地址（以为我有一辈子可以认识你），我想给你个惊喜，也想起我答应你的种种，就想着从生日先来吧，后来心中有了一个很理工男的答案，就是你现在看到的样子。计划着做成时间轴的样子，有了更多的回忆就可以加到里面。好吧，都不知道在说什么了，总之慢慢就有了这个网站，有了就开始想怎么写，写什么才能表达你对我的意义呢（你知道，我是一个抓不住重点，总围绕在细枝末节），突然爱情的红线说断就断。有一阵子想着算了，眼前的要珍惜，失去的莫强求。但觉得如果就这样了，它无主之物，如失去灵魂一般，我讨厌这种感觉。</p>
                    <p>微信上我希望以我为最后的结尾，结束这一切，事实上我希望一切都能以我结束，这样显得很恰当。那天晚上就很多事突然寻上来，我应接不暇，在那一天结束之前，我没有理会，零点过后，我恍惚了一下，那一刻我说：不要停止，把所有的能做的不能做的，全都去做。后来很长一段时间，大脑都处于亢奋状态，我也不想停止，不然总是会止不住的想。工作做完，疯狂的麻木自己。在第五天的晚上，那一瞬间安安静静的，所有的负面情绪席卷而来，可我只是很平静的看着它们，我告知自己，所谓爱情，只是一座摇摇欲坠的丰碑罢了。后来我一直在逃避写这份信，一方面是觉得，既然都已经被告知结束了，那就不要再纠缠不清，不要频繁的出现在你的生活中。但一想到，这是这么久来，我一直在为你准备，只能为你做的，我想说我答应的快，是因为脑海早已构思好的确有想法，这个时候恰巧提了出来，有时候有些也没有，但我也会记在备忘录里，炸鸡甜辣的、肯德基、电影、火锅、喜欢芒果却又过敏、橙汁、bulabula。转念一想，这些也字字诛心。其实这个网页也很不起眼，可这一切都关于我们，一直缺一个很正式的句号，可是呢，画上句号也代表我们很快就有一个新的开始。6号可能是我假期来睡得最早的一天，一方面我是在逃避，一方面我知道什么也没有，果然，静静悄悄（后来那天晚上你发来了短信，那天晚上做梦了，梦中我们复合了，我是那么的开心，突然间醒来，突然就抓起手机，以为是真的，害，假假的）。十八岁的时候，我用《这一年我二十一岁》改成我的十八岁：“这一年我十八岁，在我一生的黄金时代。我有好多奢望。我想爱，想吃，还想再一瞬间变成天上半阴半暗的云，想和我喜欢的人到处旅行，坐在海边看最美的日出日落”。一眨眼，这一年我二十岁，我不愿在想有的没的爱恋，我站在我自己这边独自一人，爱恋不过是一场高烧，思念是紧跟着的好不的咳。我很想歇斯底里，一想，没什么用，看着就太作了而且太不坚强了，不符合我的样子，（换个背景音乐^.^）我没有抱怨过任何一个人，每个人都有做自己事情的理由，只能说好巧不巧我碰到了，害，可能跟我也有关系吧，要不然怎么我遇到了。我说我知道这种玩意降临不到自己身上，可还是真诚祝福每一个人，只是你说吧，我也不奢求它，只是觉得可笑，它连我一次次生日都挺不过去，我本来很重仪式感，却也就觉得除可笑外很无所谓了。
                </p>
                    <p>有一天微博上弹出来“女朋友要跟我因为疫情分手”有一条评论说，什么都不要做，等见一面再说。我可能有些消极的想假如她心里都已经认定的话，你不可能改变一个人的心，就像我也改变不了你的一样，可我跟你还是属于特殊嘛，如果那个人真有可能的话，去见一面，或许见一面就好了，毕竟像2020ABAB的年，每隔101年才能出现一次啊，比一个世纪还要长，所以在这样一个特别的年份里，陪你度过的人一定是特别的，请珍惜，请善待。这场疫情摧毁很多，可也带来很多。我跟你说过，我不觉得这场疫情就是疫情，其实我蛮期待的，就像电影里演的03年非典一样，不顾一切的去见一个人，这场记忆是独一无二的。害，好像言多必失吧，说多快说的多，背后是空空的，是一个很切实的百日空想家。可我是吗？不知道，好像是的吧，毕竟什么都没做，也不经意间毁掉很多，你说要不给我找个借口吧，就说大概是因为没有机会。算了，还是不找借口了，白日空想家嘛，听起来也很欢乐，就像逗逼青年欢乐多一样。分手，你应该不会苦恼，其实也不必苦恼，我不希望伤害到你或让你难受，我可以受伤伤害，或难受，毕竟我是男生，但不想你如此。
                </p>
				 <p>《大话西游》里，至尊宝说“曾经有一份真挚的爱情摆在我的面前，我没有珍惜，等到失去的时候才追悔莫及，人世间最痛苦的事情莫过于此。如果上天能够给我一个重新来过的机会，我会对那个女孩子说三个字：我爱你。如果非要给这份爱加上一个期限，我希望是，一万年。”后来至尊宝成了周星驰也成了凡人，我们都是凡人，会经历生老病死，对于凡人来说，一万年太久，只争朝夕。与你，第一次从夜里见到你，总想看着你的的眼睛，那么小眨眼间却有星光闪烁，路上，觉得你像精灵一样，地铁上，你累了的样子，很心疼，想抱着你，你说我当时是不是应该勇敢的抱一下，可能就不会有后来，但我们有了第一次拥抱。我庆幸认识你之后的每一天我都在没有错过，都在一直珍惜着你，只是很抱歉让你失望，很难过在你难受的时候我没有在你身边，你哭的时候我不知所措的样子。现在我真的好想你，想你的声音，想你的笑容，想你的一切，请允许我对你再说一次，我爱你。</p>
                    <p>害，本来吧就想简简单单祝福你生日快乐，再加上，希望你安好，一切顺顺利利，快快乐乐，不知不觉就写了很多，其实也挺好，简简单单的说太没有仪式了，而且好像大家都这么说，换来换去就几句。别人的祝福是怎么样我不知道，也无法得知，我只是想说我的，一定要快乐，身体健康，照顾好自己，遇到事情多了，就列个清单，一件一件来。除此之外自己是最重要的，我知道你也是这样想的，就不多言了。还有就是吧，我觉得我们之间还是有能让别人也酸酸的时候。希望你在这段感情里大部分时间都是快乐的。我认识你之后，我也一直很开心，害，果然言多必失，这么说，看着都像个诀别信了，我还想写信努力挽回一次，我真的好想你，分开后我在对话框上打过很多字，可我不想让你觉得这个人怎么这么烦，或许我在害怕多说一次你就离开了，就再也没有机会了。算了，不让你不开心，我要你开心。
                </p>
               
                <p>生日快乐哦！惟愿你一切安好（瞧我的记性，生日快乐怎么能没有生日呢？1、2、3它来咯！），希望你没有不开心的事情，努力的都有回报。本来这么喜庆的一个节日，被我说这么多，哈哈哈，抱歉，祝你生日快乐，每天开开心心，快快乐乐，我要你快乐！</p> 
                    <p>我不善于表达想法，写这一个网页和说那么多话也就想表达“我爱你”这简单的三个字而已，你说你听过那么多的土味情话，我借用这个模板，说煽情一点：“我的心室是单人间，只住得下你一人！”
                </p>
                    <p>最后祝你生日快乐哦！</p>
                                    <p>Ps：想到生日，就想起《龙族》里面的一段场景，是诺诺给路明非录生日快乐，哈哈，我就不录这个当背景音乐了，在这美好的一天，不该被我这五音不全毁坏。后来你常常出现在我的梦里，每次我都会说一声好想好想你。而想你，希望你每一天快乐。生日快乐！快乐如此甚好。(又被我说了很多....*.*)  </p>
                    <div style={{ textAlign: 'right' }}>
                        <p>爱你的♥Yu</p>
                        <p>2020年3月11日</p>
                    </div>
                </div>
                <audio id="audio" src={url}></audio>
            </div>

        )
    }
}
export default Main


